svg.script:
var BASE = 'https://statevec.com';
var ns = 'http://www.w3.org/2000/svg';

/* ── Secrets ── */
var STATE_SECRET = 'mpcr:ai:state';
var STATE_HASH   = '2cb87f5f6c4c76da45361c4f934bee8e3d2ed29f0439fc35fbc1ae1727059be9';
var CHECKIN_HASH = 'a0c0e74f772b453b6e0352781490c9ac4dfdc781af90b4b3f24b667557c1d4e1';
var VOTES_HASH   = '802e1abbe632e0612827bb2a79e8bc892a90e1b6188550cc587d0e3139763a10';
var Q_SECRET     = 'mpcr:ai:questions';
var Q_HASH       = '02039b6bc9f648e1ddb26a3b3d1c192c210f68fc624ad875ea2c45974f855dfc';
var COMMENT_HASH = 'f28f9c8c5d9344c36a685ebc3817b445b16d76ae1eea257514362d953a36e2e6';

/* ── Tensions ── */
var TENSIONS = [
  'Cognitive offloading vs. deep learning',
  'Personalization vs. belonging',
  'Assistance vs. authorship',
  'Innovation vs. governance'
];

/* ── State ── */
var currentPhase = 'checkin';
var currentTension = 0;
var votingOpen = false;
var activeBtn = 0;

/* ── Cached data ── */
var checkins = {};
var votes = {};
var questions = [];
var comments = [];
var qScrollOffset = 0;

/* ── DOM refs ── */
var connDot = document.getElementById('connDot');
var pollDot = document.getElementById('pollDot');
var pollStatus = document.getElementById('pollStatus');
var clockDisplay = document.getElementById('clockDisplay');
var phaseLabel = document.getElementById('phaseLabel');
var phaseDetail = document.getElementById('phaseDetail');
var btnVoteBg = document.getElementById('btnVoteBg');
var btnVoteTxt = document.getElementById('btnVoteTxt');
var writeStatus = document.getElementById('writeStatus');
var qCount = document.getElementById('qCount');
var participantCount = document.getElementById('participantCount');
var voteTotal = document.getElementById('voteTotal');
var questionsGroup = document.getElementById('questionsGroup');
var participantsGroup = document.getElementById('participantsGroup');
var commentsGroup = document.getElementById('commentsGroup');
var qScrollHint = document.getElementById('qScrollHint');

/* ── Phase button refs ── */
var phaseBgs = [];
var phaseTxts = [];
for (var i = 0; i < 6; i++) {
  phaseBgs.push(document.getElementById('btnPhase' + i + 'bg'));
  phaseTxts.push(document.getElementById('btnPhase' + i + 'txt'));
}

/* ── Clock ── */
function updateClock() {
  var d = new Date();
  clockDisplay.textContent = d.toLocaleTimeString();
}
setInterval(updateClock, 1000);
updateClock();

/* ── Highlight active phase button ── */
function highlightPhase(idx) {
  activeBtn = idx;
  for (var i = 0; i < 6; i++) {
    if (i === idx) {
      phaseBgs[i].setAttribute('fill', '#c9a227');
      phaseBgs[i].setAttribute('stroke', '#c9a227');
      phaseTxts[i].setAttribute('fill', '#0a0e1a');
      phaseTxts[i].setAttribute('font-weight', 'bold');
    } else {
      phaseBgs[i].setAttribute('fill', '#0a0e1a');
      phaseBgs[i].setAttribute('stroke', '#1e293b');
      phaseTxts[i].setAttribute('fill', '#94a3b8');
      phaseTxts[i].setAttribute('font-weight', 'normal');
    }
  }
}

/* ── Update phase display ── */
function updatePhaseDisplay() {
  if (currentPhase === 'checkin') {
    phaseLabel.textContent = 'Phase: Welcome / Check-in';
    phaseDetail.textContent = 'Participants joining...';
  } else if (currentPhase === 'results') {
    phaseLabel.textContent = 'Phase: Results';
    phaseDetail.textContent = 'Reviewing all tensions';
  } else {
    phaseLabel.textContent = 'Phase: Tension ' + (currentTension + 1);
    phaseDetail.textContent = TENSIONS[currentTension];
  }
}

/* ── Voting button display ── */
function updateVoteButton() {
  if (votingOpen) {
    btnVoteBg.setAttribute('fill', '#166534');
    btnVoteBg.setAttribute('stroke', '#22c55e');
    btnVoteTxt.setAttribute('fill', '#22c55e');
    btnVoteTxt.textContent = 'Close Voting';
  } else {
    btnVoteBg.setAttribute('fill', '#0a0e1a');
    btnVoteBg.setAttribute('stroke', '#1e293b');
    btnVoteTxt.setAttribute('fill', '#94a3b8');
    btnVoteTxt.textContent = 'Open Voting';
  }
}

/* ── Write state to server (PUT) ── */
async function writeState() {
  var stateObj = {
    phase: currentPhase,
    currentTension: currentTension,
    votingOpen: votingOpen,
    updatedAt: Date.now()
  };
  try {
    var r = await fetch(BASE + '/v', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ key: STATE_SECRET, val: stateObj, ttl: 86400 })
    });
    if (r.ok) {
      writeStatus.textContent = 'state written ' + new Date().toLocaleTimeString();
      writeStatus.setAttribute('fill', '#22c55e');
      connDot.setAttribute('fill', '#22c55e');
    } else {
      writeStatus.textContent = 'write failed: ' + r.status;
      writeStatus.setAttribute('fill', '#ef4444');
    }
  } catch (e) {
    writeStatus.textContent = 'write error: ' + e.message;
    writeStatus.setAttribute('fill', '#ef4444');
    connDot.setAttribute('fill', '#ef4444');
  }
}

/* ── Phase button handlers ── */
document.getElementById('btnPhase0').addEventListener('click', function () {
  currentPhase = 'checkin';
  highlightPhase(0);
  updatePhaseDisplay();
  writeState();
});
document.getElementById('btnPhase1').addEventListener('click', function () {
  currentPhase = 'tension';
  currentTension = 0;
  highlightPhase(1);
  updatePhaseDisplay();
  writeState();
});
document.getElementById('btnPhase2').addEventListener('click', function () {
  currentPhase = 'tension';
  currentTension = 1;
  highlightPhase(2);
  updatePhaseDisplay();
  writeState();
});
document.getElementById('btnPhase3').addEventListener('click', function () {
  currentPhase = 'tension';
  currentTension = 2;
  highlightPhase(3);
  updatePhaseDisplay();
  writeState();
});
document.getElementById('btnPhase4').addEventListener('click', function () {
  currentPhase = 'tension';
  currentTension = 3;
  highlightPhase(4);
  updatePhaseDisplay();
  writeState();
});
document.getElementById('btnPhase5').addEventListener('click', function () {
  currentPhase = 'results';
  highlightPhase(5);
  updatePhaseDisplay();
  writeState();
});

/* ── Voting toggle ── */
document.getElementById('btnVote').addEventListener('click', function () {
  votingOpen = !votingOpen;
  updateVoteButton();
  writeState();
});

/* ── Reset ── */
document.getElementById('btnReset').addEventListener('click', function () {
  currentPhase = 'checkin';
  currentTension = 0;
  votingOpen = false;
  highlightPhase(0);
  updatePhaseDisplay();
  updateVoteButton();
  writeState();
});

/* ── Render participants ── */
function renderParticipants() {
  while (participantsGroup.firstChild) participantsGroup.removeChild(participantsGroup.firstChild);
  var keys = Object.keys(checkins);
  participantCount.textContent = keys.length;
  var roleColors = {
    educator: '#3b82f6',
    researcher: '#22c55e',
    policymaker: '#c9a227',
    student: '#ef4444'
  };
  var maxShow = 16;
  for (var i = 0; i < Math.min(keys.length, maxShow); i++) {
    var entry = checkins[keys[i]];
    var name = (entry && entry.name) ? entry.name : keys[i];
    var role = (entry && entry.role) ? entry.role : 'participant';
    var y = i * 16;

    var dot = document.createElementNS(ns, 'circle');
    dot.setAttribute('cx', 4);
    dot.setAttribute('cy', y + 6);
    dot.setAttribute('r', 3);
    dot.setAttribute('fill', roleColors[role] || '#94a3b8');
    participantsGroup.appendChild(dot);

    var nameEl = document.createElementNS(ns, 'text');
    nameEl.setAttribute('x', 14);
    nameEl.setAttribute('y', y + 10);
    nameEl.setAttribute('font-family', 'monospace');
    nameEl.setAttribute('font-size', '9');
    nameEl.setAttribute('fill', '#f1f5f9');
    nameEl.textContent = name.substring(0, 18);
    participantsGroup.appendChild(nameEl);

    var badge = document.createElementNS(ns, 'text');
    badge.setAttribute('x', 160);
    badge.setAttribute('y', y + 10);
    badge.setAttribute('font-family', 'monospace');
    badge.setAttribute('font-size', '7');
    badge.setAttribute('fill', roleColors[role] || '#94a3b8');
    badge.textContent = role.substring(0, 12).toUpperCase();
    participantsGroup.appendChild(badge);
  }
  if (keys.length > maxShow) {
    var more = document.createElementNS(ns, 'text');
    more.setAttribute('x', 0);
    more.setAttribute('y', maxShow * 16 + 10);
    more.setAttribute('font-family', 'monospace');
    more.setAttribute('font-size', '8');
    more.setAttribute('fill', '#94a3b8');
    more.textContent = '+ ' + (keys.length - maxShow) + ' more';
    participantsGroup.appendChild(more);
  }
}

/* ── Render vote distribution ── */
function renderVotes() {
  var tensionKey = 't' + currentTension;
  var dist = (votes && votes[tensionKey]) ? votes[tensionKey] : {};
  var total = 0;
  var counts = [0, 0, 0, 0, 0];
  for (var v = 1; v <= 5; v++) {
    counts[v - 1] = dist[String(v)] || 0;
    total += counts[v - 1];
  }
  voteTotal.textContent = total + ' votes';
  var maxCount = Math.max(1, Math.max.apply(null, counts));
  var maxBarW = 200;
  for (var j = 0; j < 5; j++) {
    var bar = document.getElementById('vbar' + (j + 1));
    var ct = document.getElementById('vcount' + (j + 1));
    bar.setAttribute('width', (counts[j] / maxCount) * maxBarW);
    ct.textContent = counts[j];
  }
}

/* ── Render questions ── */
function renderQuestions() {
  while (questionsGroup.firstChild) questionsGroup.removeChild(questionsGroup.firstChild);
  var tensionKey = 't' + currentTension;
  var filtered = [];
  if (Array.isArray(questions)) {
    for (var i = 0; i < questions.length; i++) {
      if (questions[i] && questions[i].tension === tensionKey) {
        filtered.push(questions[i]);
      }
    }
  } else if (questions && typeof questions === 'object') {
    var qkeys = Object.keys(questions);
    for (var k = 0; k < qkeys.length; k++) {
      var q = questions[qkeys[k]];
      if (q && q.tension === tensionKey) {
        q._key = qkeys[k];
        filtered.push(q);
      }
    }
  }
  /* Sort by upvotes descending */
  filtered.sort(function (a, b) { return (b.upvotes || 0) - (a.upvotes || 0); });
  qCount.textContent = '(' + filtered.length + ')';
  var maxVisible = 15;
  var startIdx = qScrollOffset;
  if (startIdx > Math.max(0, filtered.length - maxVisible)) startIdx = Math.max(0, filtered.length - maxVisible);
  var endIdx = Math.min(filtered.length, startIdx + maxVisible);

  for (var j = startIdx; j < endIdx; j++) {
    var q2 = filtered[j];
    var y = (j - startIdx) * 34;
    var highlighted = q2.highlighted === true;

    /* Background */
    var bg = document.createElementNS(ns, 'rect');
    bg.setAttribute('x', 0);
    bg.setAttribute('y', y);
    bg.setAttribute('width', 276);
    bg.setAttribute('height', 30);
    bg.setAttribute('rx', 3);
    bg.setAttribute('fill', highlighted ? '#1e293b' : '#111827');
    bg.setAttribute('stroke', highlighted ? '#c9a227' : '#1e293b');
    questionsGroup.appendChild(bg);

    /* Text */
    var txt = document.createElementNS(ns, 'text');
    txt.setAttribute('x', 6);
    txt.setAttribute('y', y + 13);
    txt.setAttribute('font-family', 'monospace');
    txt.setAttribute('font-size', '8');
    txt.setAttribute('fill', highlighted ? '#c9a227' : '#f1f5f9');
    txt.textContent = (q2.text || '').substring(0, 38);
    questionsGroup.appendChild(txt);

    /* Upvote count */
    var uv = document.createElementNS(ns, 'text');
    uv.setAttribute('x', 240);
    uv.setAttribute('y', y + 13);
    uv.setAttribute('font-family', 'monospace');
    uv.setAttribute('font-size', '8');
    uv.setAttribute('fill', '#3b82f6');
    uv.setAttribute('text-anchor', 'end');
    uv.textContent = (q2.upvotes || 0);
    questionsGroup.appendChild(uv);

    /* Author (small, below) */
    var auth = document.createElementNS(ns, 'text');
    auth.setAttribute('x', 6);
    auth.setAttribute('y', y + 24);
    auth.setAttribute('font-family', 'monospace');
    auth.setAttribute('font-size', '7');
    auth.setAttribute('fill', '#94a3b8');
    auth.textContent = q2.author || '';
    questionsGroup.appendChild(auth);

    /* Star button */
    var star = document.createElementNS(ns, 'text');
    star.setAttribute('x', 262);
    star.setAttribute('y', y + 24);
    star.setAttribute('font-family', 'monospace');
    star.setAttribute('font-size', '10');
    star.setAttribute('fill', highlighted ? '#c9a227' : '#94a3b8');
    star.setAttribute('text-anchor', 'middle');
    star.setAttribute('style', 'cursor:pointer');
    star.textContent = '\u2605';
    star.setAttribute('data-qidx', String(j));
    star.addEventListener('click', (function (qItem) {
      return function () { highlightQuestion(qItem); };
    })(q2));
    questionsGroup.appendChild(star);
  }

  if (filtered.length > maxVisible) {
    qScrollHint.textContent = 'showing ' + (startIdx + 1) + '-' + endIdx + ' of ' + filtered.length;
  } else {
    qScrollHint.textContent = '';
  }
}

/* ── Highlight a question (PATCH merge) ── */
async function highlightQuestion(q) {
  var updatedQ = {};
  for (var k in q) { if (q.hasOwnProperty(k)) updatedQ[k] = q[k]; }
  updatedQ.highlighted = !q.highlighted;
  try {
    var patchKey = q._key || null;
    if (patchKey) {
      var mergeVal = {};
      mergeVal[patchKey] = updatedQ;
      await fetch(BASE + '/v', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ key: Q_SECRET, op: 'merge', val: mergeVal })
      });
    } else if (Array.isArray(questions)) {
      /* For array-based storage, find index and rebuild */
      var idx = -1;
      for (var i = 0; i < questions.length; i++) {
        if (questions[i].text === q.text && questions[i].tension === q.tension) {
          idx = i;
          break;
        }
      }
      if (idx >= 0) {
        questions[idx].highlighted = updatedQ.highlighted;
        await fetch(BASE + '/v', {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ key: Q_SECRET, val: questions, ttl: 86400 })
        });
      }
    }
    pollAll();
  } catch (e) {
    writeStatus.textContent = 'star error: ' + e.message;
    writeStatus.setAttribute('fill', '#ef4444');
  }
}

/* ── Render comments ── */
function renderComments() {
  while (commentsGroup.firstChild) commentsGroup.removeChild(commentsGroup.firstChild);
  var list = [];
  if (Array.isArray(comments)) {
    list = comments.slice(-5).reverse();
  } else if (comments && typeof comments === 'object') {
    var ck = Object.keys(comments);
    for (var i = 0; i < ck.length; i++) {
      list.push(comments[ck[i]]);
    }
    list.sort(function (a, b) { return (b.t || 0) - (a.t || 0); });
    list = list.slice(0, 5);
  }
  for (var j = 0; j < list.length; j++) {
    var c = list[j];
    var y = j * 22;
    var nameEl = document.createElementNS(ns, 'text');
    nameEl.setAttribute('x', 0);
    nameEl.setAttribute('y', y + 10);
    nameEl.setAttribute('font-family', 'monospace');
    nameEl.setAttribute('font-size', '8');
    nameEl.setAttribute('fill', '#c9a227');
    nameEl.textContent = (c.name || c.from || 'anon').substring(0, 10);
    commentsGroup.appendChild(nameEl);

    var textEl = document.createElementNS(ns, 'text');
    textEl.setAttribute('x', 70);
    textEl.setAttribute('y', y + 10);
    textEl.setAttribute('font-family', 'monospace');
    textEl.setAttribute('font-size', '8');
    textEl.setAttribute('fill', '#f1f5f9');
    textEl.textContent = (c.text || '').substring(0, 28);
    commentsGroup.appendChild(textEl);
  }
}

/* ── Scroll questions via keyboard ── */
document.addEventListener('keydown', function (e) {
  if (e.key === 'ArrowDown') { qScrollOffset++; renderQuestions(); }
  if (e.key === 'ArrowUp' && qScrollOffset > 0) { qScrollOffset--; renderQuestions(); }
});

/* ── Poll all endpoints ── */
async function pollAll() {
  pollDot.setAttribute('fill', '#3b82f6');
  pollStatus.textContent = 'polling...';
  var ok = true;

  /* State */
  try {
    var r1 = await fetch(BASE + '/v/' + STATE_HASH);
    if (r1.ok) {
      var d1 = await r1.json();
      if (d1.val) {
        currentPhase = d1.val.phase || 'checkin';
        currentTension = d1.val.currentTension || 0;
        votingOpen = d1.val.votingOpen || false;
        /* Sync button highlight */
        if (currentPhase === 'checkin') highlightPhase(0);
        else if (currentPhase === 'results') highlightPhase(5);
        else highlightPhase(currentTension + 1);
        updatePhaseDisplay();
        updateVoteButton();
      }
    }
  } catch (e) { ok = false; }

  /* Check-ins */
  try {
    var r2 = await fetch(BASE + '/v/' + CHECKIN_HASH);
    if (r2.ok) {
      var d2 = await r2.json();
      if (d2.val) {
        checkins = d2.val;
        renderParticipants();
      }
    }
  } catch (e) { ok = false; }

  /* Votes */
  try {
    var r3 = await fetch(BASE + '/v/' + VOTES_HASH);
    if (r3.ok) {
      var d3 = await r3.json();
      if (d3.val) {
        votes = d3.val;
        renderVotes();
      }
    }
  } catch (e) { ok = false; }

  /* Questions */
  try {
    var r4 = await fetch(BASE + '/v/' + Q_HASH);
    if (r4.ok) {
      var d4 = await r4.json();
      if (d4.val) {
        questions = d4.val;
        renderQuestions();
      }
    }
  } catch (e) { ok = false; }

  /* Comments */
  try {
    var r5 = await fetch(BASE + '/v/' + COMMENT_HASH);
    if (r5.ok) {
      var d5 = await r5.json();
      if (d5.val) {
        comments = d5.val;
        renderComments();
      }
    }
  } catch (e) { ok = false; }

  if (ok) {
    pollDot.setAttribute('fill', '#22c55e');
    connDot.setAttribute('fill', '#22c55e');
    pollStatus.textContent = 'connected';
  } else {
    pollDot.setAttribute('fill', '#ef4444');
    pollStatus.textContent = 'error';
  }
}

/* ── Init ── */
highlightPhase(0);
updatePhaseDisplay();
updateVoteButton();
pollAll();
setInterval(pollAll, 2000);
